mapper.select:
SELECT d.id, d.user_id, d.dept_id, d.doctor_name, d.title, d.specialty, d.doctor_desc, d.avatar, d.status, dept.dept_name, u.username FROM hos_doctor d LEFT JOIN hos_department dept ON d.dept_id = dept.id LEFT JOIN sys_user u ON d.user_id = u.id WHERE d.deleted = 0
AND d.dept_id = #{params.deptId}
AND d.doctor_name LIKE CONCAT('%', #{params.doctorName}, '%')
AND d.status = #{params.status}
ORDER BY d.create_time DESC
